const out = [];
for (const item of $input.all()) {
  const p = (item.json && item.json.payload) ? item.json.payload : item.json;
  const ev = p.scheduled_event || {};
  const start = ev.start_time || p.start_time;
  const d = start ? new Date(start) : new Date();
  const fecha = d.toLocaleDateString('es-CO', { timeZone: 'America/Bogota', day: 'numeric', month: 'long' });
  const hora = d.toLocaleTimeString('es-CO', { timeZone: 'America/Bogota', hour: 'numeric', minute: '2-digit', hour12: true });
  const creado = new Date(p.created_at || Date.now()).toLocaleString('es-CO', { timeZone: 'America/Bogota' });
  let asesor = '';
  if (Array.isArray(ev.event_memberships) && ev.event_memberships.length) asesor = ev.event_memberships[0].user_name || '';
  let telefono = '';
  const qa = p.questions_and_answers || [];
  for (const q of qa) { if (/tel|phone|celular|whats/i.test(q.question || '')) { telefono = q.answer || ''; break; } }
  const nombre = (p.name || '') + (telefono ? ' · ' + telefono : '');
  out.push({ json: { 'Fecha en que agendó': creado, 'Nombre': nombre, 'Fecha de la cita': fecha, 'Hora de la cita': hora, 'Asesor comercial': asesor, 'Estado': 'Agendó' } });
}
return out;
